import React, { useState, useRef, useEffect } from 'react';
import { Download, Crown, Trophy, Gem, Calendar, Palette, Upload, Image as ImageIcon, X, Layout, Save } from 'lucide-react';
const AwardGenerator = () => {
  // 嘗試從 localStorage 讀取儲存的底圖
  const [savedBg, setSavedBg] = useState(null);
  useEffect(() => {
    try {
      const bg = localStorage.getItem('b1690_custom_bg');
      if (bg) setSavedBg(bg);
    } catch (e) {
      console.error("讀取底圖失敗", e);
    }
  }, []);
  const [data, setData] = useState({
    name: '陳小美',
    product: 'PFK', 
    fyp: '100,000',
    fyc: '35,000',
    date: new Date().toISOString().split('T')[0],
    image: null, 
    bgImage: null, 
  });
  // 當 savedBg 讀取到後，更新到 data
  useEffect(() => {
    if (savedBg) {
      setData(prev => ({ ...prev, bgImage: savedBg }));
    }
  }, [savedBg]);
  // 鎖定大紅色系 (無切換功能)
  const currentTheme = {
      name: '帝王熱血紅',
      bgGradient: 'from-[#450a0a] via-[#2a0a0a] to-black',
      glowColor: 'bg-red-500/20',
      borderColor: 'border-white/30',
      buttonClass: 'bg-red-900 ring-red-500',
      accentColor: 'text-red-100'
  };

  const canvasRef = useRef(null);
  // 圖片壓縮函數 (解決 localStorage 額度問題)
  const compressImage = (file, callback) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target.result;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX_WIDTH = 800; // 限制最大寬度
        const scaleSize = MAX_WIDTH / img.width;

        if (scaleSize >= 1) {
            callback(event.target.result);
            return;
        }
        canvas.width = MAX_WIDTH;
        canvas.height = img.height * scaleSize;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, canvas.width, canvas.height);

        const dataUrl = canvas.toDataURL('image/jpeg', 0.7);
        callback(dataUrl);
      };
    };
  };
  // 自動儲存底圖
  useEffect(() => {
    if (data.bgImage) {
      try {
        localStorage.setItem('b1690_custom_bg', data.bgImage);
      } catch (e) {
        console.error("圖片檔案太大，無法快取 (QuotaExceededError)", e);
      }
    } else {
        if (savedBg === null && data.bgImage === null) {
             // do nothing
        } else if (data.bgImage === null) {
             localStorage.removeItem('b1690_custom_bg');
        }
    }
  }, [data.bgImage, savedBg]);
  const handleChange = (e) => {
    const { name, value } = e.target;
    setData(prev => ({ ...prev, [name]: value }));
  };
  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setData(prev => ({ ...prev, image: reader.result }));
      };
      reader.readAsDataURL(file);
    }
  };
  const handleBgUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      compressImage(file, (compressedResult) => {
          setData(prev => ({ ...prev, bgImage: compressedResult }));
      });
    }
  };
  const removeImage = () => {
    setData(prev => ({ ...prev, image: null }));
  };
  const removeBgImage = () => {
    setData(prev => ({ ...prev, bgImage: null }));
    localStorage.removeItem('b1690_custom_bg');
  };
  const downloadImage = () => {
    alert("建議使用電腦或手機的「截圖」功能來保存賀報，以獲得最佳解析度！");
  };
  const getFontSize = (str) => {
    if (!str) return 'text-4xl';
    const len = str.toString().length;
    if (len > 10) return 'text-2xl';
    if (len > 7) return 'text-3xl';
    return 'text-4xl';
  };
  return (
    <div className={`min-h-screen p-4 md:p-8 font-sans text-slate-200 transition-colors duration-500 bg-slate-900`}>
      <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-12 gap-8 items-start">

        {/* 左側：輸入區 */}
        <div className="md:col-span-4 space-y-6 sticky top-8">
          <div className="bg-slate-800/80 backdrop-blur border border-slate-700 rounded-xl shadow-2xl p-6">
            <div className="border-b border-slate-700 pb-4 mb-6">
              <h1 className="text-xl font-bold text-white flex items-center gap-2">
                <Palette className="w-6 h-6" />
                中恩賀報產生器
              </h1>
              <p className="text-slate-400 text-xs mt-1">B1690 專屬紅金版</p>
            </div>
            <div className="space-y-5">
               {/* 底圖上傳區 */}
               <div className="bg-slate-700/30 p-3 rounded-lg border border-slate-600 relative overflow-hidden">
                <label className="block text-xs font-bold uppercase text-slate-300 mb-2 tracking-wider flex items-center gap-2">
                  <Layout className="w-3 h-3" /> 1. 底圖設定 (您想要的背景)
                  {data.bgImage && <span className="text-green-400 text-[10px] ml-auto flex items-center gap-1"><Save className="w-3 h-3" />已自動記憶</span>}
                </label>

                {!data.bgImage ? (
                  <label className="flex flex-col items-center justify-center w-full h-24 border-2 border-slate-500 border-dashed rounded-lg cursor-pointer bg-slate-800 hover:bg-slate-700 hover:border-white transition-all group">
                    <div className="flex flex-col items-center justify-center pt-2 pb-3">
                      <Upload className="w-6 h-6 mb-2 text-slate-400 group-hover:text-white animate-bounce" />
                      <p className="text-xs text-slate-300 group-hover:text-white font-bold">點此上傳您指定的底圖</p>
                    </div>
                    <input type="file" className="hidden" accept="image/*" onChange={handleBgUpload} />
                  </label>
                ) : (
                  <div className="relative w-full h-24 rounded-lg overflow-hidden border border-white/30 group">
                    <img src={data.bgImage} alt="Bg Preview" className="w-full h-full object-cover" />
                    <div className="absolute inset-0 flex items-center justify-center bg-black/40 group-hover:bg-black/20 transition-colors">
                       <span className="text-xs text-white px-2 py-1 rounded backdrop-blur-sm shadow-lg font-bold">
                         使用中 (點擊右上角更換)
                       </span>
                    </div>
                    <button 
                      onClick={removeBgImage}
                      className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-full hover:bg-red-500 shadow-md z-10"
                      title="移除並清除記憶"
                    >
                      <X className="w-3 h-3" />
                    </button>
                  </div>
                )}
              </div>
               {/* 人物照片上傳區 */}
               <div>
                <label className="block text-xs font-bold uppercase text-slate-300 mb-2 tracking-wider flex items-center gap-2">
                  <ImageIcon className="w-3 h-3" /> 2. 人物照片
                </label>

                {!data.image ? (
                  <label className="flex flex-col items-center justify-center w-full h-20 border-2 border-slate-600 border-dashed rounded-lg cursor-pointer bg-slate-800/50 hover:bg-slate-700/50 hover:border-white/50 transition-all group">
                    <div className="flex items-center justify-center gap-2">
                      <Upload className="w-4 h-4 text-slate-400 group-hover:text-white transition-colors" />
                      <p className="text-xs text-slate-400 group-hover:text-white">上傳照片 (無照片顯示"賀")</p>
                    </div>
                    <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
                  </label>
                ) : (
                  <div className="relative w-full h-32 rounded-lg overflow-hidden border border-white/30 group">
                    <img src={data.image} alt="Preview" className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/60 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                      <button 
                        onClick={removeImage}
                        className="bg-red-600/80 text-white px-3 py-1 rounded-full flex items-center gap-2 hover:bg-red-600 text-xs"
                      >
                        <X className="w-3 h-3" /> 移除
                      </button>
                    </div>
                  </div>
                )}
              </div>
              <div>
                <label className="block text-xs font-bold uppercase text-slate-400 mb-1.5 tracking-wider">姓名</label>
                <input
                  type="text"
                  name="name"
                  value={data.name}
                  onChange={handleChange}
                  className="w-full bg-slate-900 border border-slate-600 rounded-lg p-3 focus:ring-1 focus:ring-white focus:border-white focus:outline-none text-white text-lg font-medium transition-all"
                />
              </div>
              <div>
                <label className="block text-xs font-bold uppercase text-slate-400 mb-1.5 tracking-wider">成交商品</label>
                <input
                  type="text"
                  name="product"
                  value={data.product}
                  onChange={handleChange}
                  className="w-full bg-slate-900 border border-slate-600 rounded-lg p-3 focus:ring-1 focus:ring-white focus:border-white focus:outline-none text-white transition-all"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold uppercase text-slate-400 mb-1.5 tracking-wider">FYP</label>
                  <input
                    type="text"
                    name="fyp"
                    value={data.fyp}
                    onChange={handleChange}
                    placeholder="例: 100,000"
                    className="w-full bg-slate-900 border border-slate-600 rounded-lg p-3 focus:ring-1 focus:ring-white focus:border-white focus:outline-none text-white font-mono text-lg transition-all"
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold uppercase text-slate-400 mb-1.5 tracking-wider">FYC</label>
                  <input
                    type="text"
                    name="fyc"
                    value={data.fyc}
                    onChange={handleChange}
                    placeholder="例: 35,000"
                    className="w-full bg-slate-900 border border-slate-600 rounded-lg p-3 focus:ring-1 focus:ring-white focus:border-white focus:outline-none text-white font-mono text-lg transition-all"
                  />
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold uppercase text-slate-400 mb-1.5 tracking-wider flex items-center gap-2">
                  <Calendar className="w-3 h-3" /> 報件日期
                </label>
                <input
                  type="date"
                  name="date"
                  value={data.date}
                  onChange={handleChange}
                  className="w-full bg-slate-900 border border-slate-600 rounded-lg p-3 focus:ring-1 focus:ring-white focus:border-white focus:outline-none text-white font-mono text-lg transition-all"
                />
              </div>
            </div>

            <div className="mt-8 pt-6 border-t border-slate-700">
               <button 
                  onClick={downloadImage}
                  className="w-full bg-white text-slate-900 hover:bg-slate-200 font-bold py-3 rounded-lg shadow-lg transition-all flex items-center justify-center gap-2"
               >
                 <Download className="w-5 h-5" /> 下載圖片
               </button>
               <p className="text-center text-slate-500 text-[10px] mt-2">建議直接對右側圖片進行截圖</p>
            </div>
          </div>
        </div>
        {/* 右側：預覽區 */}
        <div className="md:col-span-8 flex flex-col items-center justify-center min-h-[600px] bg-slate-800/30 rounded-2xl border border-slate-700/50 p-8">

          {/* 賀報本體 Canvas */}
          <div 
            ref={canvasRef}
            className={`w-full max-w-[480px] aspect-[4/5] relative overflow-hidden shadow-[0_20px_60px_-15px_rgba(0,0,0,0.8)] rounded-xl bg-black text-white group transition-all duration-500`}
          >
            {/* 1. 背景層 */}
            <div className="absolute inset-0 z-0 overflow-hidden flex items-center justify-center">
               {data.bgImage ? (
                 <img src={data.bgImage} alt="Background" className="absolute inset-0 w-full h-full object-cover" />
               ) : (
                 <>
                   {/* 預設: 帝王熱血紅 (鎖定) */}
                   <div className={`absolute inset-0 bg-[radial-gradient(circle_at_top,_var(--tw-gradient-stops))] ${currentTheme.bgGradient} transition-all duration-500`}></div>
                   <div className="absolute inset-0 opacity-30 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')]"></div>
                   <div className={`absolute top-[-10%] left-[-10%] w-[60%] h-[60%] ${currentTheme.glowColor} blur-[100px] rounded-full`}></div>
                   <div className={`absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] ${currentTheme.glowColor} blur-[80px] rounded-full`}></div>
                 </>
               )}
            </div>
            {/* 2. 邊框層 - 純白 */}
            <div className="absolute inset-4 z-10 pointer-events-none">
              <div className={`absolute inset-0 border border-white/30 rounded-sm`}></div>
              <div className={`absolute inset-1 border border-white/10 rounded-sm`}></div>
              {/* 四角華麗裝飾 - 純白 */}
              <div className="absolute top-0 left-0 w-16 h-16 border-t-[3px] border-l-[3px] border-white/60 rounded-tl-sm"></div>
              <div className="absolute top-0 right-0 w-16 h-16 border-t-[3px] border-r-[3px] border-white/60 rounded-tr-sm"></div>
              <div className="absolute bottom-0 left-0 w-16 h-16 border-b-[3px] border-l-[3px] border-white/60 rounded-bl-sm"></div>
              <div className="absolute bottom-0 right-0 w-16 h-16 border-b-[3px] border-r-[3px] border-white/60 rounded-br-sm"></div>
            </div>
            {/* 3. 內容層 */}
            <div className="absolute inset-0 z-20 flex flex-col items-center pt-12 pb-6 px-6 text-center font-sans">

              {/* --- 頂部：圓形頭像/賀字 + 姓名 --- */}
              <div className="flex flex-col items-center justify-center mb-6">
                {/* 圓形區域 - 特大版 (w-52 h-52) */}
                <div className="relative w-52 h-52 mb-4 rounded-full border-[4px] border-white/80 shadow-[0_0_30px_rgba(255,255,255,0.4)] overflow-hidden bg-black/20 backdrop-blur-sm flex items-center justify-center transform hover:scale-105 transition-transform duration-500">
                  {data.image ? (
                    <img src={data.image} alt="User" className="w-full h-full object-cover" />
                  ) : (
                    <span className="text-9xl font-black font-serif text-white drop-shadow-md">賀</span>
                  )}
                </div>
                {/* 姓名 */}
                <h2 className="text-4xl md:text-5xl font-black text-white tracking-widest drop-shadow-[0_4px_4px_rgba(0,0,0,0.8)] font-serif whitespace-nowrap leading-tight">
                  {data.name}
                </h2>
              </div>
              {/* --- 中間：整合式數據框 (無底板模式) --- */}
              <div className="w-full max-w-[360px] border-[3px] border-white rounded-2xl overflow-hidden backdrop-blur-sm shadow-2xl">
                {/* 上半部：成交商品 */}
                <div className="py-3 text-center border-b border-white/30 bg-black/20">
                  <p className="text-xl font-bold text-white tracking-wider drop-shadow-md">
                    成交 {data.product}
                  </p>
                </div>
                {/* 下半部：FYP / FYC 數據並排 (無深色底) */}
                <div className="flex relative bg-black/10">
                   {/* 中間分隔線 */}
                   <div className="absolute inset-y-3 left-1/2 w-[1.5px] bg-white/30"></div>
                  {/* FYP */}
                  <div className="flex-1 py-5 flex flex-col items-center justify-center">
                     <div className="text-xs font-bold text-white/90 uppercase tracking-widest mb-1 drop-shadow-md">FYP</div>
                     <div className={`${getFontSize(data.fyp)} font-black text-white font-mono tracking-tighter leading-none drop-shadow-xl`}>
                       {data.fyp || '0'}
                     </div>
                  </div>
                  {/* FYC */}
                  <div className="flex-1 py-5 flex flex-col items-center justify-center">
                     <div className="text-xs font-bold text-white/90 uppercase tracking-widest mb-1 flex items-center gap-1 drop-shadow-md">
                       <Gem className="w-3 h-3" /> FYC
                     </div>
                     <div className={`${getFontSize(data.fyc)} font-black text-white font-mono tracking-tighter leading-none drop-shadow-xl`}>
                       {data.fyc || '0'}
                     </div>
                  </div>
                </div>
              </div>
              {/* --- 底部：Spacer & Footer --- */}
              <div className="flex-1"></div> {/* 撐開空間 */}

              {/* Footer: 單位 & 日期 */}
              <div className="flex flex-col items-center justify-end pb-2 opacity-90">
                 <div className={`flex items-center gap-2 mb-1`}>
                    <span className="text-xs font-bold tracking-[0.15em] text-white drop-shadow-md">B1690</span>
                    <span className="text-xs text-white opacity-60">|</span>
                    <span className="text-sm font-bold tracking-[0.2em] text-white drop-shadow-md">中恩通訊處</span>
                 </div>
                 <span className="text-base font-bold text-white font-mono tracking-[0.2em] drop-shadow-md">
                   {data.date.replace(/-/g, '.')}
                 </span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};
export default AwardGenerator;

