import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  Download, 
  Gem, 
  Calendar, 
  Palette, 
  Upload, 
  Image as ImageIcon, 
  X, 
  Layout, 
  Save, 
  Loader2,
  CheckCircle2
} from 'lucide-react';
import { toPng } from 'html-to-image';

// --- Types ---
interface AwardData {
  name: string;
  product: string;
  fyp: string;
  fyc: string;
  date: string;
  image: string | null;
  bgImage: string | null;
}

const DEFAULT_DATA: AwardData = {
  name: '陳小美',
  product: 'PFK',
  fyp: '100,000',
  fyc: '35,000',
  date: new Date().toISOString().split('T')[0],
  image: null,
  bgImage: null,
};

// --- Constants ---
const STORAGE_KEY = 'b1690_custom_bg_v2';

const THEME = {
  name: '帝王熱血紅',
  bgGradient: 'from-[#450a0a] via-[#2a0a0a] to-black',
  glowColor: 'bg-red-500/20',
  borderColor: 'border-white/30',
  buttonClass: 'bg-red-900 ring-red-500',
  accentColor: 'text-red-100'
};

const App: React.FC = () => {
  const [data, setData] = useState<AwardData>(DEFAULT_DATA);
  const [isDownloading, setIsDownloading] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const awardRef = useRef<HTMLDivElement>(null);

  // Load saved background on mount
  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        setData(prev => ({ ...prev, bgImage: saved }));
      }
    } catch (e) {
      console.error("Failed to load background from storage", e);
    }
  }, []);

  // Save background to localStorage when it changes
  useEffect(() => {
    if (data.bgImage) {
      try {
        localStorage.setItem(STORAGE_KEY, data.bgImage);
      } catch (e) {
        // Handle quota exceeded gracefully
        if (e instanceof DOMException && e.name === 'QuotaExceededError') {
          console.warn("Storage quota exceeded, background image might be too large.");
        }
      }
    }
  }, [data.bgImage]);

  // Image processing helpers
  const compressImage = (file: File, callback: (result: string) => void) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target?.result as string;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX_WIDTH = 1200; // Increase resolution for better quality
        const scaleSize = MAX_WIDTH / img.width;

        if (scaleSize >= 1) {
          callback(event.target?.result as string);
          return;
        }

        canvas.width = MAX_WIDTH;
        canvas.height = img.height * scaleSize;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
          callback(dataUrl);
        }
      };
    };
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setData(prev => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'image' | 'bgImage') => {
    const file = e.target.files?.[0];
    if (file) {
      compressImage(file, (result) => {
        setData(prev => ({ ...prev, [field]: result }));
      });
    }
  };

  const clearImage = (field: 'image' | 'bgImage') => {
    setData(prev => ({ ...prev, [field]: null }));
    if (field === 'bgImage') {
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  const downloadImage = async () => {
    if (!awardRef.current || isDownloading) return;

    setIsDownloading(true);
    try {
      // Small delay to ensure any hover states are cleared or fonts are ready
      await new Promise(resolve => setTimeout(resolve, 100));

      const dataUrl = await toPng(awardRef.current, {
        cacheBust: true,
        pixelRatio: 2, // Higher density for crisp images
        style: {
          transform: 'scale(1)',
          transformOrigin: 'top left',
        }
      });

      const link = document.createElement('a');
      link.download = `中恩賀報_${data.name}_${data.date}.png`;
      link.href = dataUrl;
      link.click();

      setShowSuccess(true);
      setTimeout(() => setShowSuccess(false), 3000);
    } catch (err) {
      console.error('Download failed:', err);
      alert('下載失敗。這可能是因為圖片檔案太大或瀏覽器限制。建議您改用手機截圖功能。');
    } finally {
      setIsDownloading(false);
    }
  };

  const getFontSize = (str: string) => {
    const len = str.length;
    if (len > 12) return 'text-xl';
    if (len > 10) return 'text-2xl';
    if (len > 7) return 'text-3xl';
    return 'text-4xl';
  };

  return (
    <div className="min-h-screen p-4 md:p-8 text-slate-200 bg-slate-900 transition-colors duration-500">
      <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

        {/* Left Section: Controls */}
        <div className="lg:col-span-4 space-y-6 lg:sticky lg:top-8 order-2 lg:order-1">
          <div className="bg-slate-800/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl shadow-2xl p-6 overflow-hidden">
            <div className="border-b border-slate-700/50 pb-4 mb-6 relative">
              <h1 className="text-2xl font-black text-white flex items-center gap-3">
                <Palette className="w-7 h-7 text-red-500" />
                中恩賀報產生器
              </h1>
              <p className="text-slate-400 text-xs mt-1 uppercase tracking-widest font-bold">Insurance Elite Award Creator</p>
            </div>

            <div className="space-y-5">
              {/* Background Upload */}
              <div className="bg-slate-700/20 p-4 rounded-xl border border-slate-600/50 relative">
                <label className="block text-xs font-bold uppercase text-slate-400 mb-3 tracking-wider flex items-center justify-between">
                  <span className="flex items-center gap-2"><Layout className="w-4 h-4" /> 1. 背景底圖設定</span>
                  {data.bgImage && <span className="text-emerald-400 text-[10px] flex items-center gap-1 bg-emerald-400/10 px-2 py-0.5 rounded-full"><Save className="w-3 h-3" />已自動記憶</span>}
                </label>

                {!data.bgImage ? (
                  <label className="flex flex-col items-center justify-center w-full h-24 border-2 border-slate-600 border-dashed rounded-xl cursor-pointer bg-slate-800/50 hover:bg-slate-700 hover:border-red-500/50 transition-all group">
                    <div className="flex flex-col items-center justify-center">
                      <Upload className="w-7 h-7 mb-2 text-slate-500 group-hover:text-red-400 group-hover:animate-bounce" />
                      <p className="text-xs text-slate-400 group-hover:text-white font-bold">點此上傳自定義底圖</p>
                    </div>
                    <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'bgImage')} />
                  </label>
                ) : (
                  <div className="relative w-full h-24 rounded-xl overflow-hidden border border-white/20 group">
                    <img src={data.bgImage} alt="Background Preview" className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                      <p className="text-xs text-white font-bold bg-black/50 px-3 py-1 rounded-full backdrop-blur-md">更換底圖</p>
