                  </>
                )}
                {!isDownloading && !showSuccess && (
                  <div className="absolute inset-0 bg-red-500/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                )}
              </button>
              <p className="text-center text-slate-500 text-[11px] font-bold">
                專業提示：高解析度輸出，支援電腦與行動裝置。
              </p>
            </div>
          </div>
        </div>

        {/* Right Section: Preview Area */}
        <div className="lg:col-span-8 flex flex-col items-center justify-center min-h-[600px] bg-slate-800/20 rounded-3xl border border-slate-700/30 p-6 md:p-12 order-1 lg:order-2">

