            <div className="w-12 h-[1px] bg-slate-700"></div>
          </div>

          {/* Capture Target */}
          <div 
            ref={awardRef}
            className="w-full max-w-[480px] aspect-[4/5] relative overflow-hidden shadow-[0_40px_100px_-20px_rgba(0,0,0,0.9)] rounded-2xl bg-black text-white group"
          >
            {/* Background Layers */}
            <div className="absolute inset-0 z-0 overflow-hidden flex items-center justify-center">
               {data.bgImage ? (
