            <div className="absolute inset-0 z-20 flex flex-col items-center pt-16 pb-8 px-8 text-center font-sans">

              {/* Profile Image & Name Section */}
              <div className="flex flex-col items-center justify-center mb-10 w-full">
                <div className="relative w-56 h-56 mb-6 rounded-full border-[5px] border-white/90 shadow-[0_15px_45px_rgba(0,0,0,0.7),0_0_40px_rgba(255,255,255,0.2)] overflow-hidden bg-black/40 backdrop-blur-md flex items-center justify-center">
                  {data.image ? (
