                <h2 className="text-5xl md:text-6xl font-black text-white tracking-[0.2em] drop-shadow-[0_8px_15px_rgba(0,0,0,0.9)] font-serif-tc whitespace-nowrap leading-tight mb-2">
                  {data.name}
                </h2>
                <div className="h-[2px] w-24 bg-gradient-to-r from-transparent via-white/50 to-transparent"></div>
              </div>

              {/* Stats Box */}
              <div className="w-full max-w-[360px] border-[4px] border-white rounded-[2rem] overflow-hidden backdrop-blur-md shadow-[0_30px_60px_-15px_rgba(0,0,0,0.8)] bg-black/20">
                {/* Header: Product */}
                <div className="py-4 text-center border-b border-white/40 bg-white/10 relative overflow-hidden">
                  <div className="absolute inset-0 bg-gradient-to-b from-white/10 to-transparent"></div>
                  <p className="text-2xl font-black text-white tracking-[0.15em] drop-shadow-[0_2px_4px_rgba(0,0,0,0.5)] relative z-10">
                    成交 {data.product}
