                {/* Body: FYP / FYC */}
                <div className="flex relative items-stretch">
                  <div className="absolute inset-y-6 left-1/2 w-[1px] bg-white/40"></div>

                  {/* FYP */}
                  <div className="flex-1 py-8 px-2 flex flex-col items-center justify-center min-w-0">
                     <div className="text-[10px] font-black text-white/80 uppercase tracking-[0.3em] mb-2 drop-shadow-md whitespace-nowrap">FYP</div>
