import React, { useState, useRef, useEffect } from 'react';
import { 
  Download, 
  Gem, 
  Calendar, 
  Palette, 
  Upload, 
  Image as ImageIcon, 
  X, 
  Layout, 
  Save, 
  Loader2,
  CheckCircle2
} from 'lucide-react';
import { toPng } from 'html-to-image';

// --- Types ---
interface AwardData {
  name: string;
  product: string;
  fyp: string;
  fyc: string;
  date: string;
  image: string | null;
  bgImage: string | null;
}

const DEFAULT_DATA: AwardData = {
  name: '陳小美',
  product: 'PFK',
  fyp: '100,000',
  fyc: '35,000',
  date: new Date().toISOString().split('T')[0],
  image: null,
  bgImage: null,
};

// --- Constants ---
const STORAGE_KEY = 'b1690_custom_bg_v2';

const THEME = {
  name: '帝王熱血紅',
  bgGradient: 'from-[#450a0a] via-[#2a0a0a] to-black',
  glowColor: 'bg-red-500/20',
  borderColor: 'border-white/30',
  buttonClass: 'bg-red-900 ring-red-500',
  accentColor: 'text-red-100'
};

const App: React.FC = () => {
  const [data, setData] = useState<AwardData>(DEFAULT_DATA);
  const [isDownloading, setIsDownloading] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const awardRef = useRef<HTMLDivElement>(null);

  // Load saved background on mount
  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        setData(prev => ({ ...prev, bgImage: saved }));
      }
    } catch (e) {
      console.error("Failed to load background from storage", e);
    }
  }, []);

  // Save background to localStorage
  useEffect(() => {
    if (data.bgImage) {
      try {
        localStorage.setItem(STORAGE_KEY, data.bgImage);
      } catch (e) {
        if (e instanceof DOMException && e.name === 'QuotaExceededError') {
          console.warn("Storage quota exceeded");
        }
      }
    }
  }, [data.bgImage]);

  const compressImage = (file: File, callback: (result: string) => void) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target?.result as string;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX_WIDTH = 1200; 
        const scaleSize = MAX_WIDTH / img.width;
        if (scaleSize >= 1) {
          callback(event.target?.result as string);
          return;
        }
        canvas.width = MAX_WIDTH;
        canvas.height = img.height * scaleSize;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          callback(canvas.toDataURL('image/jpeg', 0.85));
        }
      };
    };
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setData(prev => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'image' | 'bgImage') => {
    const file = e.target.files?.[0];
    if (file) {
      compressImage(file, (result) => {
        setData(prev => ({ ...prev, [field]: result }));
      });
    }
  };

  const clearImage = (field: 'image' | 'bgImage') => {
    setData(prev => ({ ...prev, [field]: null }));
    if (field === 'bgImage') localStorage.removeItem(STORAGE_KEY);
  };

  const downloadImage = async () => {
    if (!awardRef.current || isDownloading) return;
    setIsDownloading(true);
    try {
      await new Promise(resolve => setTimeout(resolve, 150));
      const dataUrl = await toPng(awardRef.current, {
        cacheBust: true,
        pixelRatio: 2,
        style: { transform: 'scale(1)', transformOrigin: 'top left' }
      });
      const link = document.createElement('a');
      link.download = `中恩賀報_${data.name}_${data.date}.png`;
      link.href = dataUrl;
      link.click();
      setShowSuccess(true);
      setTimeout(() => setShowSuccess(false), 3000);
    } catch (err) {
      alert('下載失敗，建議直接長按預覽圖進行儲存。');
    } finally {
      setIsDownloading(false);
    }
  };

  // 優化字體縮放邏輯，確保數字不被裁切
  const getFontSize = (val: string) => {
    const str = val || '0';
    const len = str.length;
    if (len > 14) return 'text-lg';
    if (len > 11) return 'text-xl';
    if (len > 9) return 'text-2xl';
    if (len > 7) return 'text-3xl';
    return 'text-4xl';
  };

  return (
    <div className="min-h-screen p-4 md:p-8 text-slate-200 bg-slate-900 transition-colors duration-500">
      <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

        {/* 左側控制欄 */}
        <div className="lg:col-span-4 space-y-6 lg:sticky lg:top-8 order-2 lg:order-1">
          <div className="bg-slate-800/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl shadow-2xl p-6">
            <div className="border-b border-slate-700/50 pb-4 mb-6">
              <h1 className="text-2xl font-black text-white flex items-center gap-3">
                <Palette className="w-7 h-7 text-red-500" />
                中恩賀報產生器
              </h1>
              <p className="text-slate-400 text-[10px] mt-1 uppercase tracking-widest font-bold">Insurance Elite Award Creator</p>
            </div>

            <div className="space-y-5">
              {/* 底圖上傳 */}
              <div className="bg-slate-700/20 p-4 rounded-xl border border-slate-600/50">
                <label className="block text-xs font-bold uppercase text-slate-400 mb-3 flex items-center justify-between">
                  <span className="flex items-center gap-2"><Layout className="w-4 h-4" /> 1. 背景底圖設定</span>
                  {data.bgImage && <span className="text-emerald-400 text-[10px] flex items-center gap-1 bg-emerald-400/10 px-2 py-0.5 rounded-full"><Save className="w-3 h-3" />已儲存</span>}
                </label>
                {!data.bgImage ? (
                  <label className="flex flex-col items-center justify-center w-full h-24 border-2 border-slate-600 border-dashed rounded-xl cursor-pointer hover:border-red-500/50 transition-all bg-slate-800/50 group">
                    <Upload className="w-7 h-7 mb-2 text-slate-500 group-hover:text-red-400 group-hover:animate-bounce" />
                    <p className="text-xs text-slate-400 font-bold">點此上傳底圖</p>
                    <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'bgImage')} />
                  </label>
                ) : (
                  <div className="relative w-full h-24 rounded-xl overflow-hidden border border-white/20 group">
                    <img src={data.bgImage} alt="Bg" className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                      <p className="text-xs text-white font-bold bg-black/50 px-3 py-1 rounded-full">更換</p>
                      <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" onChange={(e) => handleImageUpload(e, 'bgImage')} />
                    </div>
                    <button onClick={() => clearImage('bgImage')} className="absolute top-2 right-2 bg-red-600 text-white p-1.5 rounded-full hover:bg-red-500 shadow-xl z-10"><X className="w-4 h-4" /></button>
                  </div>
                )}
              </div>

              {/* 照片上傳 */}
              <div className="bg-slate-700/20 p-4 rounded-xl border border-slate-600/50">
                <label className="block text-xs font-bold uppercase text-slate-400 mb-3 flex items-center gap-2">
                  <ImageIcon className="w-4 h-4" /> 2. 人物照片
                </label>
                {!data.image ? (
                  <label className="flex flex-col items-center justify-center w-full h-20 border-2 border-slate-600 border-dashed rounded-xl cursor-pointer hover:border-red-500/50 transition-all bg-slate-800/50 group">
                    <Upload className="w-5 h-5 text-slate-500 group-hover:text-white mr-2 inline" />
                    <p className="text-xs text-slate-400 font-bold inline">選擇照片</p>
                    <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'image')} />
                  </label>
                ) : (
                  <div className="relative w-full h-24 rounded-xl overflow-hidden border border-white/20 group">
                    <img src={data.image} alt="Avatar" className="w-full h-full object-cover" />
                    <button onClick={() => clearImage('image')} className="absolute top-2 right-2 bg-red-600 text-white p-1.5 rounded-full hover:bg-red-500 shadow-xl z-10"><X className="w-4 h-4" /></button>
                  </div>
                )}
              </div>

              {/* 輸入欄位 */}
              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-tighter">姓名</label>
                    <input type="text" name="name" value={data.name} onChange={handleInputChange} className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white font-bold outline-none focus:ring-2 focus:ring-red-500/50" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-tighter">成交商品</label>
                    <input type="text" name="product" value={data.product} onChange={handleInputChange} className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white font-bold outline-none focus:ring-2 focus:ring-red-500/50" />
                  </div>
                </div>
