import React, { useState, useRef, useEffect } from 'react';
import { 
  Download, 
  Gem, 
  Calendar, 
  Palette, 
  Upload, 
  Image as ImageIcon, 
  X, 
  Layout, 
  Save, 
  Loader2,
  CheckCircle2
} from 'lucide-react';
import { toPng } from 'html-to-image';

// --- Types ---
interface AwardData {
  name: string;
  product: string;
  fyp: string;
  fyc: string;
  date: string;
  image: string | null;
  bgImage: string | null;
}

const DEFAULT_DATA: AwardData = {
  name: '陳小美',
  product: 'PFK',
  fyp: '100,000',
  fyc: '35,000',
  date: new Date().toISOString().split('T')[0],
  image: null,
  bgImage: null,
};

// --- Constants ---
const STORAGE_KEY = 'b1690_custom_bg_v3';

const THEME = {
  name: '帝王熱血紅',
  bgGradient: 'from-[#450a0a] via-[#2a0a0a] to-black',
  glowColor: 'bg-red-500/20',
  borderColor: 'border-white/30',
  buttonClass: 'bg-red-900 ring-red-500',
  accentColor: 'text-red-100'
};

const App: React.FC = () => {
  const [data, setData] = useState<AwardData>(DEFAULT_DATA);
  const [isDownloading, setIsDownloading] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [previewScale, setPreviewScale] = useState(1);
  const awardRef = useRef<HTMLDivElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);

  // 處理行動裝置預覽縮放，確保不裁切
  useEffect(() => {
    const handleResize = () => {
      if (previewContainerRef.current && window.innerWidth < 1024) {
        const containerWidth = previewContainerRef.current.offsetWidth - 48; // padding
        const targetWidth = 480; // 賀報原始設計寬度
        if (containerWidth < targetWidth) {
          setPreviewScale(containerWidth / targetWidth);
        } else {
          setPreviewScale(1);
        }
      } else {
        setPreviewScale(1);
      }
    };

    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Load saved background
  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        setData(prev => ({ ...prev, bgImage: saved }));
      }
    } catch (e) {
      console.error("Failed to load background", e);
    }
  }, []);

  // Save background
  useEffect(() => {
    if (data.bgImage) {
      try {
        localStorage.setItem(STORAGE_KEY, data.bgImage);
      } catch (e) {
        console.warn("Storage quota exceeded");
      }
    }
  }, [data.bgImage]);

  const compressImage = (file: File, callback: (result: string) => void) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target?.result as string;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX_WIDTH = 1200; 
        const scaleSize = MAX_WIDTH / img.width;
        if (scaleSize >= 1) {
          callback(event.target?.result as string);
          return;
        }
        canvas.width = MAX_WIDTH;
        canvas.height = img.height * scaleSize;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          callback(canvas.toDataURL('image/jpeg', 0.85));
        }
      };
    };
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setData(prev => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'image' | 'bgImage') => {
    const file = e.target.files?.[0];
    if (file) {
      compressImage(file, (result) => {
        setData(prev => ({ ...prev, [field]: result }));
      });
    }
  };

  const clearImage = (field: 'image' | 'bgImage') => {
    setData(prev => ({ ...prev, [field]: null }));
    if (field === 'bgImage') localStorage.removeItem(STORAGE_KEY);
  };

  const downloadImage = async () => {
    if (!awardRef.current || isDownloading) return;
    setIsDownloading(true);
    try {
      await new Promise(resolve => setTimeout(resolve, 300));

      const dataUrl = await toPng(awardRef.current, {
        cacheBust: true,
        pixelRatio: 3, // 更高解析度
        style: { 
          transform: 'scale(1)', 
          transformOrigin: 'top left',
          borderRadius: '0' 
        }
      });

      const link = document.createElement('a');
      link.download = `中恩賀報_${data.name}_${data.date}.png`;
      link.href = dataUrl;
      link.click();

      setShowSuccess(true);
      setTimeout(() => setShowSuccess(false), 3000);
    } catch (err) {
      alert('下載失敗，建議改用截圖功能。');
    } finally {
      setIsDownloading(false);
    }
