  const getFontSize = (val: string) => {
    const str = val || '0';
    const len = str.length;
    if (len > 14) return 'text-lg';
    if (len > 11) return 'text-xl';
    if (len > 9) return 'text-2xl';
    if (len > 7) return 'text-3xl';
    return 'text-4xl';
