  return (
    <div className="min-h-screen p-4 md:p-8 text-slate-200 bg-slate-950 font-sans">
      <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

        {/* 控制面板 */}
