                <label className="block text-xs font-bold uppercase text-slate-400 mb-3 flex items-center justify-between">
                  <span className="flex items-center gap-2"><Layout className="w-4 h-4" /> 1. 背景底圖</span>
                  {data.bgImage && <span className="text-emerald-400 text-[10px] flex items-center gap-1 bg-emerald-400/10 px-2 py-0.5 rounded-full"><Save className="w-3 h-3" />已紀錄</span>}
