                    <Upload className="w-7 h-7 mb-2 text-slate-600 group-hover:text-red-400" />
                    <p className="text-xs text-slate-500 font-bold">點此上傳自定義背景</p>
                    <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'bgImage')} />
