                    </div>
                    <button onClick={() => clearImage('bgImage')} className="absolute top-2 right-2 bg-red-600 text-white p-1.5 rounded-full hover:bg-red-500"><X className="w-4 h-4" /></button>
                  </div>
                )}
              </div>

              <div className="bg-slate-800/50 p-4 rounded-2xl border border-slate-700">
                <label className="block text-xs font-bold uppercase text-slate-400 mb-3 flex items-center gap-2">
