                </label>
                {!data.image ? (
                  <label className="flex flex-col items-center justify-center w-full h-20 border-2 border-slate-700 border-dashed rounded-xl cursor-pointer hover:border-red-500/50 transition-all bg-slate-950/50 group">
                    <Upload className="w-5 h-5 text-slate-600 group-hover:text-white mr-2" />
                    <p className="text-xs text-slate-500 font-bold">選擇照片</p>
                    <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'image')} />
                  </label>
                ) : (
                  <div className="relative w-full h-24 rounded-xl overflow-hidden border border-white/10 group">
                    <img src={data.image} alt="Avatar" className="w-full h-full object-cover" />
                    <button onClick={() => clearImage('image')} className="absolute top-2 right-2 bg-red-600 text-white p-1.5 rounded-full hover:bg-red-500"><X className="w-4 h-4" /></button>
                  </div>
                )}
              </div>

              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider">姓名</label>
                    <input type="text" name="name" value={data.name} onChange={handleInputChange} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-white font-bold focus:ring-2 focus:ring-red-500/50 outline-none" />
