            <div className="mt-8 pt-6 border-t border-slate-800">
              <button 
                onClick={downloadImage} 
                disabled={isDownloading} 
                className={`w-full py-4 rounded-2xl shadow-xl transition-all active:scale-[0.98] flex items-center justify-center gap-3 text-lg font-black ${showSuccess ? 'bg-emerald-600 text-white' : 'bg-white text-slate-950 hover:bg-slate-100'}`}
              >
                {isDownloading ? <Loader2 className="w-6 h-6 animate-spin" /> : showSuccess ? <CheckCircle2 className="w-6 h-6" /> : <Download className="w-6 h-6" />}
                {isDownloading ? '製圖中...' : showSuccess ? '下載成功！' : '下載賀報圖片'}
