} from 'lucide-react';
import { toPng } from 'html-to-image';

// --- Types ---
interface AwardData {
  name: string;
  product: string;
  fyp: string;
  fyc: string;
  date: string;
  image: string | null;
  bgImage: string | null;
  sheetUrl?: string;
}

const DEFAULT_DATA: AwardData = {
  name: '陳小美',
  product: 'PFK',
  fyp: '100,000',
  fyc: '35,000',
  date: new Date().toISOString().split('T')[0],
  image: null,
  bgImage: null,
  sheetUrl: '',
};

const STORAGE_KEY = 'b1690_custom_bg_v4';
const SHEET_URL_KEY = 'b1690_sheet_url';

const THEME = {
  name: '帝王熱血紅',
  bgGradient: 'from-[#450a0a] via-[#2a0a0a] to-black',
  glowColor: 'bg-red-500/20',
};

const App: React.FC = () => {
  const [data, setData] = useState<AwardData>(DEFAULT_DATA);
  const [isDownloading, setIsDownloading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [previewScale, setPreviewScale] = useState(1);
  const awardRef = useRef<HTMLDivElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleResize = () => {
      if (previewContainerRef.current && window.innerWidth < 1024) {
        const containerWidth = previewContainerRef.current.offsetWidth - 48;
        const targetWidth = 480;
        setPreviewScale(containerWidth < targetWidth ? containerWidth / targetWidth : 1);
      } else {
        setPreviewScale(1);
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    try {
      const savedBg = localStorage.getItem(STORAGE_KEY);
      const savedSheet = localStorage.getItem(SHEET_URL_KEY);
      if (savedBg || savedSheet) {
        setData(prev => ({ 
          ...prev, 
          bgImage: savedBg || prev.bgImage,
          sheetUrl: savedSheet || prev.sheetUrl 
        }));
      }
    } catch (e) { console.error(e); }
  }, []);

  useEffect(() => {
    if (data.bgImage) localStorage.setItem(STORAGE_KEY, data.bgImage);
    if (data.sheetUrl) localStorage.setItem(SHEET_URL_KEY, data.sheetUrl);
  }, [data.bgImage, data.sheetUrl]);

  // Google Drive 連結轉換器
  const fixGoogleDriveUrl = (url: string) => {
    if (url.includes('drive.google.com/file/d/')) {
      const id = url.split('/d/')[1]?.split('/')[0];
      return `https://lh3.googleusercontent.com/u/0/d/${id}=w1000`;
    }
    return url;
  };

  const syncWithSheet = async () => {
    if (!data.sheetUrl || !data.name) {
      alert("請先輸入 Google Sheet CSV 連結與姓名");
      return;
    }
    setIsSyncing(true);
    try {
      const response = await fetch(data.sheetUrl);
      const csvText = await response.text();
      const rows = csvText.split('\n').map(row => row.split(',').map(cell => cell.trim().replace(/"/g, '')));

      const headers = rows[0];
      const targetRow = rows.find(row => row.includes(data.name));

      if (targetRow) {
        const getVal = (label: string) => {
          const idx = headers.findIndex(h => h.includes(label));
          return idx !== -1 ? targetRow[idx] : '';
        };

        setData(prev => ({
          ...prev,
          product: getVal('成交商品') || getVal('商品') || prev.product,
          fyp: getVal('FYP') || prev.fyp,
          fyc: getVal('FYC') || prev.fyc,
          image: fixGoogleDriveUrl(getVal('照片') || getVal('照片連結') || '') || prev.image
        }));
        setShowSuccess(true);
        setTimeout(() => setShowSuccess(false), 2000);
      } else {
        alert(`在試算表中找不到姓名：「${data.name}」`);
      }
    } catch (err) {
      alert("連線失敗，請確保試算表已「發佈到網路」並選擇 CSV 格式。");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setData(prev => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'image' | 'bgImage') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => setData(prev => ({ ...prev, [field]: ev.target?.result as string }));
      reader.readAsDataURL(file);
    }
  };

  const downloadImage = async () => {
    if (!awardRef.current || isDownloading) return;
    setIsDownloading(true);
    try {
      await new Promise(r => setTimeout(r, 400));
      const dataUrl = await toPng(awardRef.current, {
        cacheBust: true,
        pixelRatio: 3,
        style: { transform: 'scale(1)', transformOrigin: 'top left', borderRadius: '0' }
      });
      const link = document.createElement('a');
      link.download = `中恩賀報_${data.name}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) { alert('下載失敗，建議直接截圖。'); }
    finally { setIsDownloading(false); }
  };

  const getFontSize = (val: string) => {
    const len = (val || '0').length;
    if (len > 11) return 'text-xl';
    if (len > 8) return 'text-2xl';
    if (len > 6) return 'text-3xl';
    return 'text-4xl';
  };

  return (
    <div className="min-h-screen p-4 md:p-8 text-slate-200 bg-slate-950 font-sans">
      <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* 控制面板 */}
        <div className="lg:col-span-4 space-y-6 lg:sticky lg:top-8 order-2 lg:order-1">
          <div className="bg-slate-900/80 backdrop-blur-2xl border border-slate-800 rounded-3xl p-6 shadow-2xl">
            <div className="border-b border-slate-800 pb-4 mb-6">
              <h1 className="text-2xl font-black text-white flex items-center gap-3">
                <Palette className="w-7 h-7 text-red-500" />
                中恩賀報 Pro
              </h1>
              <p className="text-slate-500 text-[10px] mt-1 uppercase tracking-widest font-bold">B1690 Elite Generator</p>
            </div>

            <div className="space-y-4">
              {/* Google Sheet Sync */}
              <div className="bg-blue-500/10 p-4 rounded-2xl border border-blue-500/20">
                <label className="block text-[10px] font-black text-blue-400 mb-2 uppercase tracking-wider flex items-center gap-2">
                  <LinkIcon className="w-3 h-3" /> 雲端連動 (CSV 連結)
                </label>
                <div className="flex gap-2">
                  <input 
