import React, { useState, useRef, useEffect } from 'react';
import { 
  Download, 
  Gem, 
  Calendar, 
  Palette, 
  Upload, 
  Image as ImageIcon, 
  X, 
  Layout, 
  Save, 
  Loader2,
  CheckCircle2,
  RefreshCw,
  Link as LinkIcon,
  Cloud
} from 'lucide-react';
import { toPng } from 'html-to-image';

// --- Types ---
interface AwardData {
  name: string;
  product: string;
  fyp: string;
  fyc: string;
  date: string;
  image: string | null;
  bgImage: string | null;
  sheetUrl?: string;
}

const DEFAULT_DATA: AwardData = {
  name: '陳小美',
  product: 'PFK',
  fyp: '100,000',
  fyc: '35,000',
  date: new Date().toISOString().split('T')[0],
  image: null,
  bgImage: null,
  sheetUrl: '',
};

const BG_STORAGE_KEY = 'b1690_permanent_bg';
const SHEET_URL_KEY = 'b1690_sheet_config';

const THEME = {
  name: '帝王熱血紅',
  bgGradient: 'from-[#450a0a] via-[#2a0a0a] to-black',
  glowColor: 'bg-red-500/20',
};

const App: React.FC = () => {
  const [data, setData] = useState<AwardData>(DEFAULT_DATA);
  const [isDownloading, setIsDownloading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [previewScale, setPreviewScale] = useState(1);
  const awardRef = useRef<HTMLDivElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);

  // 處理行動裝置縮放
  useEffect(() => {
    const handleResize = () => {
      if (previewContainerRef.current && window.innerWidth < 1024) {
        const containerWidth = previewContainerRef.current.offsetWidth - 48;
        const targetWidth = 480;
        setPreviewScale(containerWidth < targetWidth ? containerWidth / targetWidth : 1);
      } else {
        setPreviewScale(1);
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // 載入持久化設定 (底圖與試算表網址)
  useEffect(() => {
    try {
      const savedBg = localStorage.getItem(BG_STORAGE_KEY);
      const savedSheet = localStorage.getItem(SHEET_URL_KEY);
      setData(prev => ({ 
        ...prev, 
        bgImage: savedBg || null,
        sheetUrl: savedSheet || '' 
      }));
    } catch (e) { console.error("Storage error", e); }
  }, []);

  // 儲存設定
  useEffect(() => {
    if (data.bgImage) localStorage.setItem(BG_STORAGE_KEY, data.bgImage);
    if (data.sheetUrl) localStorage.setItem(SHEET_URL_KEY, data.sheetUrl);
  }, [data.bgImage, data.sheetUrl]);

  // Google Drive 連結轉換 (轉為直接載入格式)
  const convertDriveUrl = (url: string) => {
    if (url.includes('drive.google.com/file/d/')) {
      const match = url.match(/\/d\/(.+?)\//);
      const id = match ? match[1] : null;
      return id ? `https://lh3.googleusercontent.com/u/0/d/${id}=w1000` : url;
    }
    return url;
  };

  // 同步試算表資料
  const syncWithSheet = async () => {
    if (!data.sheetUrl || !data.name) {
      alert("請先輸入『試算表 CSV 連結』以及『人員姓名』");
      return;
    }
    setIsSyncing(true);
    try {
      const response = await fetch(data.sheetUrl);
      if (!response.ok) throw new Error("Fetch failed");
      const csvText = await response.text();
      const rows = csvText.split('\n').map(row => 
        row.split(',').map(cell => cell.trim().replace(/"/g, ''))
      );

      const headers = rows[0];
      const targetRow = rows.find(row => row.includes(data.name));

      if (targetRow) {
        const getVal = (labels: string[]) => {
          const idx = headers.findIndex(h => labels.some(l => h.includes(l)));
          return idx !== -1 ? targetRow[idx] : null;
        };

        setData(prev => ({
          ...prev,
          product: getVal(['成交商品', '商品']) || prev.product,
          fyp: getVal(['FYP', '金額']) || prev.fyp,
          fyc: getVal(['FYC']) || prev.fyc,
          image: getVal(['照片', '連結', '頭像']) ? convertDriveUrl(getVal(['照片', '連結', '頭像'])!) : prev.image
        }));
        setShowSuccess(true);
        setTimeout(() => setShowSuccess(false), 2000);
      } else {
        alert(`在雲端試算表中找不到姓名：「${data.name}」`);
      }
    } catch (err) {
      alert("雲端連線失敗！請確認您的試算表已「發佈到網路」並選擇「CSV」格式。");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setData(prev => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'image' | 'bgImage') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const result = ev.target?.result as string;
        setData(prev => ({ ...prev, [field]: result }));
      };
      reader.readAsDataURL(file);
    }
  };

  const clearImage = (field: 'image' | 'bgImage') => {
    setData(prev => ({ ...prev, [field]: null }));
    if (field === 'bgImage') localStorage.removeItem(BG_STORAGE_KEY);
  };

  const downloadImage = async () => {
    if (!awardRef.current || isDownloading) return;
    setIsDownloading(true);
    try {
      await new Promise(r => setTimeout(r, 400));
      const dataUrl = await toPng(awardRef.current, {
        cacheBust: true,
        pixelRatio: 3,
        style: { transform: 'scale(1)', transformOrigin: 'top left', borderRadius: '0' }
      });
      const link = document.createElement('a');
      link.download = `B1690賀報_${data.name}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) { alert('下載失敗，建議直接對預覽圖進行截圖保存。'); }
    finally { setIsDownloading(false); }
  };

  const getFontSize = (val: string) => {
    const len = (val || '0').length;
    if (len > 12) return 'text-xl';
    if (len > 9) return 'text-2xl';
    if (len > 7) return 'text-3xl';
    return 'text-4xl';
  };

  return (
    <div className="min-h-screen p-4 md:p-8 text-slate-200 bg-slate-950 font-sans">
      <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* 左側：控制面板 */}
        <div className="lg:col-span-4 space-y-6 lg:sticky lg:top-8 order-2 lg:order-1">
          <div className="bg-slate-900/90 backdrop-blur-2xl border border-slate-800 rounded-[2rem] p-6 shadow-2xl">
            <div className="border-b border-slate-800 pb-4 mb-6">
              <h1 className="text-2xl font-black text-white flex items-center gap-3">
                <Palette className="w-7 h-7 text-red-500" />
                中恩賀報 Pro
              </h1>
              <p className="text-slate-500 text-[10px] mt-1 uppercase tracking-widest font-bold">B1690 Cloud Connect</p>
            </div>

            <div className="space-y-4">
              {/* Google Sheet 同步區塊 */}
              <div className="bg-red-500/5 p-4 rounded-2xl border border-red-500/20 group">
                <label className="block text-[10px] font-black text-red-400 mb-2 uppercase tracking-wider flex items-center gap-2">
                  <Cloud className="w-3 h-3" /> 雲端連動設定 (CSV 網址)
                </label>
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    name="sheetUrl" 
                    value={data.sheetUrl} 
                    onChange={handleInputChange}
                    placeholder="貼上試算表 CSV 連結" 
                    className="flex-1 bg-slate-950 border border-slate-800 rounded-lg px-3 py-2 text-[11px] font-mono outline-none focus:border-red-500 transition-colors"
                  />
                  <button 
                    onClick={syncWithSheet}
                    disabled={isSyncing}
                    title="從雲端搜尋姓名並同步資料"
                    className="bg-red-600 hover:bg-red-500 p-2.5 rounded-lg transition-colors disabled:opacity-50 shadow-lg shadow-red-900/20"
                  >
                    {isSyncing ? <Loader2 className="w-4 h-4 animate-spin text-white" /> : <RefreshCw className="w-4 h-4 text-white" />}
                  </button>
                </div>
                <p className="text-[9px] text-slate-600 mt-2 leading-relaxed">發佈為 CSV 後貼上連結，輸入姓名即可同步照片與數據。</p>
              </div>

              {/* 資料輸入 */}
              <div className="space-y-3">
                <div>
                  <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider">人員姓名</label>
                  <input type="text" name="name" value={data.name} onChange={handleInputChange} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-white font-bold outline-none focus:ring-1 focus:ring-red-500" />
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div className="col-span-2">
                    <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider">成交商品</label>
                    <input type="text" name="product" value={data.product} onChange={handleInputChange} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-white font-bold outline-none focus:ring-1 focus:ring-red-500" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider">FYP</label>
                    <input type="text" name="fyp" value={data.fyp} onChange={handleInputChange} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-white font-mono outline-none focus:ring-1 focus:ring-red-500" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider">FYC</label>
                    <input type="text" name="fyc" value={data.fyc} onChange={handleInputChange} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-white font-mono outline-none focus:ring-1 focus:ring-red-500" />
                  </div>
                </div>

                <div>
                   <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider flex items-center gap-2"><Calendar className="w-3 h-3" /> 報件日期</label>
                   <input type="date" name="date" value={data.date} onChange={handleInputChange} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-white font-mono outline-none" />
                </div>
              </div>

              {/* 照片區塊 (保留手動功能) */}
              <div className="grid grid-cols-2 gap-3 pt-2">
                <div className="bg-slate-800/40 p-3 rounded-2xl border border-slate-700/50">
                  <label className="block text-[10px] font-black text-slate-500 mb-2 uppercase flex items-center gap-2"><ImageIcon className="w-3 h-3" /> 手動人物照</label>
                  <label className="flex flex-col items-center justify-center w-full h-12 border border-slate-700 border-dashed rounded-lg cursor-pointer hover:bg-slate-800 transition-colors">
                    <Upload className="w-4 h-4 text-slate-500" />
                    <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'image')} />
                  </label>
                </div>
                <div className="bg-slate-800/40 p-3 rounded-2xl border border-slate-700/50">
                  <label className="block text-[10px] font-black text-slate-500 mb-2 uppercase flex items-center gap-2"><Layout className="w-3 h-3" /> 修改底圖</label>
                  <label className="flex flex-col items-center justify-center w-full h-12 border border-slate-700 border-dashed rounded-lg cursor-pointer hover:bg-slate-800 transition-colors">
                    <Layout className="w-4 h-4 text-slate-500" />
                    <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'bgImage')} />
                  </label>
                </div>
              </div>

              <button 
                onClick={downloadImage} 
                disabled={isDownloading} 
                className={`w-full py-4 rounded-2xl shadow-xl transition-all active:scale-[0.98] flex items-center justify-center gap-3 text-lg font-black mt-2 ${showSuccess ? 'bg-emerald-600 text-white' : 'bg-white text-slate-950 hover:bg-slate-100'}`}
              >
                {isDownloading ? <Loader2 className="w-6 h-6 animate-spin" /> : showSuccess ? <CheckCircle2 className="w-6 h-6" /> : <Download className="w-6 h-6" />}
                {isDownloading ? '生成中...' : showSuccess ? '操作成功！' : '下載賀報圖片'}
              </button>
            </div>
          </div>
        </div>

        {/* 右側：預覽區域 */}
        <div ref={previewContainerRef} className="lg:col-span-8 flex flex-col items-center justify-center min-h-[500px] lg:min-h-[700px] bg-slate-900/40 rounded-[3rem] border border-slate-800 p-6 md:p-12 order-1 lg:order-2 overflow-hidden">
          <div className="mb-6 text-slate-600 text-[10px] font-black uppercase tracking-[0.8em]">PREVIEW MODE</div>

          <div style={{ transform: `scale(${previewScale})`, transformOrigin: 'center center', width: '480px', height: '600px' }} className="flex-shrink-0 transition-transform duration-300">
            <div ref={awardRef} className="w-[480px] h-[600px] relative overflow-hidden shadow-[0_50px_100px_-20px_rgba(0,0,0,1)] rounded-2xl bg-black text-white">

              {/* 背景層 (優先顯示手動上傳/記憶的底圖) */}
              <div className="absolute inset-0 z-0">
                {data.bgImage ? (
                  <img src={data.bgImage} alt="Bg" className="w-full h-full object-cover" />
                ) : (
                  <>
                    <div className={`absolute inset-0 bg-[radial-gradient(circle_at_top,_var(--tw-gradient-stops))] ${THEME.bgGradient}`}></div>
                    <div className="absolute inset-0 opacity-20 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')]"></div>
                  </>
                )}
              </div>

              {/* 邊框裝飾 */}
