                中恩賀報 Pro
              </h1>
              <p className="text-slate-500 text-[10px] mt-1 uppercase tracking-[0.3em] font-bold">B1690 Cloud Edition</p>
            </div>

            <div className="space-y-5">
              {/* 核心功能：照片更新按鈕 */}
              <button 
                onClick={syncWithSheet}
                disabled={isSyncing}
                className="w-full py-4 bg-red-600 hover:bg-red-500 text-white rounded-2xl shadow-lg shadow-red-900/40 transition-all active:scale-[0.98] flex items-center justify-center gap-3 font-black text-lg disabled:opacity-50"
              >
                {isSyncing ? <Loader2 className="w-6 h-6 animate-spin" /> : <RefreshCw className="w-6 h-6" />}
                {isSyncing ? '正在更新中...' : '照片更新'}
              </button>

              <div className="h-[1px] bg-slate-800 my-2"></div>

              {/* 資料輸入 */}
              <div className="space-y-3">
                <div>
                  <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider">人員姓名 (搜尋雲端用)</label>
                  <input type="text" name="name" value={data.name} onChange={handleInputChange} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-white font-bold outline-none focus:ring-1 focus:ring-red-500" />
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <div className="col-span-2">
                    <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider">成交商品</label>
                    <input type="text" name="product" value={data.product} onChange={handleInputChange} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-white font-bold outline-none" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider">FYP</label>
                    <input type="text" name="fyp" value={data.fyp} onChange={handleInputChange} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-white font-mono outline-none" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider">FYC</label>
                    <input type="text" name="fyc" value={data.fyc} onChange={handleInputChange} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-white font-mono outline-none" />
                  </div>
                </div>
                <div>
                   <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider flex items-center gap-2"><Calendar className="w-3 h-3" /> 報件日期</label>
                   <input type="date" name="date" value={data.date} onChange={handleInputChange} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-white font-mono outline-none" />
                </div>
              </div>

              {/* 照片與底圖上傳 */}
              <div className="grid grid-cols-2 gap-3 pt-2">
                <div className="bg-slate-800/30 p-3 rounded-2xl border border-slate-700/50">
                  <label className="block text-[10px] font-black text-slate-500 mb-2 uppercase flex items-center gap-2"><ImageIcon className="w-3 h-3" /> 手動照片</label>
                  <label className="flex flex-col items-center justify-center w-full h-14 border-2 border-slate-700 border-dashed rounded-xl cursor-pointer hover:border-slate-500 transition-all bg-slate-950/40">
                    <Upload className="w-4 h-4 text-slate-500 mb-1" />
                    <span className="text-[10px] text-slate-600 font-bold uppercase tracking-widest">Upload</span>
                    <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'image')} />
                  </label>
                </div>
                <div className="bg-slate-800/30 p-3 rounded-2xl border border-slate-700/50 relative overflow-hidden">
                  <label className="block text-[10px] font-black text-slate-500 mb-2 uppercase flex items-center justify-between">
                    <span className="flex items-center gap-2"><Layout className="w-3 h-3" /> 記憶底圖</span>
                    {data.bgImage && <button onClick={clearPermanentBg} className="text-red-500 hover:text-red-400"><Trash2 className="w-3 h-3" /></button>}
                  </label>
                  <label className="flex flex-col items-center justify-center w-full h-14 border-2 border-slate-700 border-dashed rounded-xl cursor-pointer hover:border-slate-500 transition-all bg-slate-950/40">
                    <Save className={`w-4 h-4 mb-1 ${data.bgImage ? 'text-emerald-500' : 'text-slate-500'}`} />
                    <span className="text-[10px] text-slate-600 font-bold">{data.bgImage ? '已記住' : '設底圖'}</span>
                    <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'bgImage')} />
                  </label>
                </div>
              </div>

              <button 
                onClick={downloadImage} 
                disabled={isDownloading} 
                className={`w-full py-4 rounded-2xl shadow-xl transition-all active:scale-[0.98] flex items-center justify-center gap-3 text-lg font-black mt-2 ${showSuccess ? 'bg-emerald-600 text-white' : 'bg-white text-slate-950 hover:bg-slate-100'}`}
              >
                {isDownloading ? <Loader2 className="w-6 h-6 animate-spin" /> : showSuccess ? <CheckCircle2 className="w-6 h-6" /> : <Download className="w-6 h-6" />}
                {isDownloading ? '生成中...' : showSuccess ? '操作成功！' : '下載賀報圖片'}
              </button>
            </div>
          </div>
        </div>

        {/* 右側：預覽區域 */}
        <div ref={previewContainerRef} className="lg:col-span-8 flex flex-col items-center justify-center min-h-[600px] lg:min-h-[750px] bg-slate-900/40 rounded-[3rem] border border-slate-800 p-8 order-1 lg:order-2 overflow-hidden relative">
          <div className="mb-8 text-slate-700 text-[10px] font-black uppercase tracking-[1em] flex items-center gap-4">
             <div className="w-12 h-[1px] bg-slate-800"></div> PREVIEW <div className="w-12 h-[1px] bg-slate-800"></div>
          </div>

          <div style={{ transform: `scale(${previewScale})`, transformOrigin: 'center center', width: '480px', height: '600px' }} className="flex-shrink-0 transition-all duration-500">
            <div ref={awardRef} className="w-[480px] h-[600px] relative overflow-hidden shadow-[0_60px_120px_-20px_rgba(0,0,0,1)] rounded-3xl bg-black text-white">

              {/* 1. 背景層 */}
              <div className="absolute inset-0 z-0">
                {data.bgImage ? (
                  <img src={data.bgImage} alt="Bg" className="w-full h-full object-cover" />
                ) : (
                  <>
                    <div className={`absolute inset-0 bg-[radial-gradient(circle_at_top,_var(--tw-gradient-stops))] ${THEME.bgGradient}`}></div>
                    <div className="absolute inset-0 opacity-20 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')]"></div>
                    <div className={`absolute top-[-20%] left-[-20%] w-[80%] h-[80%] ${THEME.glowColor} blur-[120px] rounded-full`}></div>
                  </>
                )}
              </div>

              {/* 2. 邊框裝飾 */}
              <div className="absolute inset-5 z-10 pointer-events-none">
                <div className="absolute inset-0 border border-white/20 rounded-sm"></div>
                <div className="absolute top-0 left-0 w-16 h-16 border-t-[3px] border-l-[3px] border-white/40"></div>
                <div className="absolute top-0 right-0 w-16 h-16 border-t-[3px] border-r-[3px] border-white/40"></div>
                <div className="absolute bottom-0 left-0 w-16 h-16 border-b-[3px] border-l-[3px] border-white/40"></div>
                <div className="absolute bottom-0 right-0 w-16 h-16 border-b-[3px] border-r-[3px] border-white/40"></div>
              </div>

              {/* 3. 內容主體 */}
              <div className="absolute inset-0 z-20 flex flex-col items-center pt-14 pb-10 px-10 text-center">

                {/* 人物區塊 */}
                <div className="flex flex-col items-center mb-6 w-full">
                  <div className="relative w-48 h-48 mb-6 rounded-full border-[6px] border-white shadow-[0_20px_50px_rgba(0,0,0,0.8)] overflow-hidden bg-black/40 flex items-center justify-center">
                    {data.image ? (
                      <img src={data.image} alt="Elite" className="w-full h-full object-cover" crossOrigin="anonymous" />
                    ) : (
                      <span className="text-[10rem] font-black font-serif-tc text-white leading-none mt-4">賀</span>
                    )}
                  </div>
                  <h2 className="text-5xl font-black text-white tracking-[0.2em] drop-shadow-[0_4px_10px_rgba(0,0,0,0.8)] font-serif-tc whitespace-nowrap mb-2">{data.name}</h2>
                  <div className="h-[1.5px] w-24 bg-gradient-to-r from-transparent via-white/60 to-transparent"></div>
                </div>

                {/* 數據看板 */}
                <div className="w-full max-w-[370px] border-[4px] border-white rounded-[2.2rem] overflow-hidden backdrop-blur-xl bg-black/30 shadow-2xl">
                  <div className="py-4 text-center border-b border-white/40 bg-white/10">
                    <p className="text-4xl font-black text-white tracking-[0.2em] uppercase truncate px-4 drop-shadow-md leading-none">
                      成交 {data.product}
                    </p>
                  </div>
                  <div className="flex relative items-stretch">
                    <div className="absolute inset-y-4 left-1/2 w-[1px] bg-white/30"></div>
                    <div className="flex-1 pt-5 pb-8 flex flex-col items-center justify-center min-w-0">
                       <span className="text-[10px] font-black text-white/90 tracking-widest mb-2 drop-shadow-sm">FYP</span>
                       <span className={`${getFontSize(data.fyp)} font-black text-white font-mono drop-shadow-2xl`}>{data.fyp || '0'}</span>
                    </div>
                    <div className="flex-1 pt-5 pb-8 flex flex-col items-center justify-center min-w-0">
                       <span className="text-[10px] font-black text-white/90 tracking-widest mb-2 flex items-center gap-1 drop-shadow-sm">
                         <Gem className="w-2.5 h-2.5 text-yellow-400" /> FYC
                       </span>
                       <span className={`${getFontSize(data.fyc)} font-black text-white font-mono drop-shadow-2xl`}>{data.fyc || '0'}</span>
                    </div>
                  </div>
                </div>

                <div className="flex-1"></div>

                {/* 底部資訊 */}
                <div className="flex flex-col items-center justify-end w-full">
                   <div className="flex items-center gap-3 mb-3 bg-black/50 px-6 py-2 rounded-full border border-white/20 backdrop-blur-md shadow-lg">
                      <span className="text-[12px] font-black tracking-widest text-white">B1690</span>
                      <div className="w-[1px] h-3 bg-white/30"></div>
                      <span className="text-[12px] font-black tracking-[0.4em] text-white">中恩通訊處</span>
                   </div>
                   <span className="text-base font-black text-white font-mono tracking-[0.5em] drop-shadow-[0_2px_4px_rgba(0,0,0,1)] brightness-125">
                     {data.date.replace(/-/g, '.')}
                   </span>
                </div>
              </div>
            </div>
          </div>

          <p className="mt-10 text-slate-700 text-[10px] font-bold text-center tracking-widest uppercase opacity-60">
            Professional Honor System · Permanent Cloud Connect Enabled
          </p>
        </div>
      </div>
    </div>
  );
};

export default App;
